const crypto = require('crypto');

function b64urlFromString(str) {
  return Buffer.from(str, 'utf8')
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

const input = $input.first().json;
const serviceAccountEmail = input.GOOGLE_SERVICE_ACCOUNT_EMAIL;
const privateKeyPem = String(input.GOOGLE_PRIVATE_KEY || '').replace(/\\n/g, '\n');
const scope = input.GOOGLE_SCOPE || 'https://www.googleapis.com/auth/spreadsheets.readonly';

if (!serviceAccountEmail || !privateKeyPem) {
  throw new Error('Missing GOOGLE_SERVICE_ACCOUNT_EMAIL or GOOGLE_PRIVATE_KEY');
}

const now = Math.floor(Date.now() / 1000);
const header = { alg: 'RS256', typ: 'JWT' };
const payload = {
  iss: serviceAccountEmail,
  scope,
  aud: 'https://oauth2.googleapis.com/token',
  iat: now,
  exp: now + 3600,
};

const encodedHeader = b64urlFromString(JSON.stringify(header));
const encodedPayload = b64urlFromString(JSON.stringify(payload));
const signingInput = `${encodedHeader}.${encodedPayload}`;

const signer = crypto.createSign('RSA-SHA256');
signer.update(signingInput);
signer.end();

const signature = signer
  .sign(privateKeyPem, 'base64')
  .replace(/=/g, '')
  .replace(/\+/g, '-')
  .replace(/\//g, '_');

const assertion = `${signingInput}.${signature}`;

return [{
  json: {
    ...input,
    assertion,
  },
}];

function toNumber(v) {
  if (v === null || v === undefined) return 0;
  const s = String(v).replace(/[$,%\s,]/g, '');
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function colToA1(colIndex1Based) {
  let n = colIndex1Based;
  let out = '';
  while (n > 0) {
    const m = (n - 1) % 26;
    out = String.fromCharCode(65 + m) + out;
    n = Math.floor((n - 1) / 26);
  }
  return out;
}

const sheet = $json; // from Webhook Read Google Sheet
const values = sheet.values || [];
const reportData = $('Extract from File').first().json.data || [];
const sheetName = $('Set Credentials').first().json.SHEET_NAME || 'MOBILITY';

// 1) Aggregate Amazon cost by SKU
const adsBySku = new Map();
for (const r of reportData) {
  const sku = (r.advertisedSku || '').trim();
  if (!sku) continue;
  const cost = toNumber(r.cost);
  adsBySku.set(sku, (adsBySku.get(sku) || 0) + cost);
}

// 2) Detect header row (last row that has SKU + ADS-like column)
const adsHeaderNames = new Set(['ADS', 'ADS_SPEND', 'Ads spend', 'Ads Spend', 'ads',
'ads_spend']);
let headerRowIdx = -1;
let skuCol = -1;
let adsCol = -1;

for (let i = 0; i < Math.min(values.length, 12); i++) {
  const row = values[i] || [];
  const skuIdx = row.findIndex(c => String(c).trim().toUpperCase() === 'SKU');
  if (skuIdx === -1) continue;

  let adsIdx = -1;
  for (let j = 0; j < row.length; j++) {
    const name = String(row[j] || '').trim();
    if (adsHeaderNames.has(name)) {
      adsIdx = j;
      break;
    }
  }
  if (adsIdx !== -1) {
    headerRowIdx = i;
    skuCol = skuIdx;
    adsCol = adsIdx;
  }
}

if (headerRowIdx === -1 || skuCol === -1 || adsCol === -1) {
  throw new Error('Could not find header row with SKU and ADS column');
}

// 3) Build Google batch updates
const data = [];
const missingSkus = [];

for (let i = headerRowIdx + 1; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  if (!sku) continue;

  if (!adsBySku.has(sku)) continue;

  const newAds = Number(adsBySku.get(sku).toFixed(2));
  const rowNumber = i + 1; // sheet is 1-based
  const adsColA1 = colToA1(adsCol + 1);

  data.push({
    range: `${sheetName}!${adsColA1}${rowNumber}`,
    values: [[newAds]]
  });
}

// Optional: SKUs from report not found in sheet
for (const sku of adsBySku.keys()) {
  const found = values.slice(headerRowIdx + 1).some(r => String((r || [])[skuCol] ||
'').trim() === sku);
  if (!found) missingSkus.push(sku);
}

return [{
  json: {
    valueInputOption: 'USER_ENTERED',
    data,
    totalUpdates: data.length,
    missingSkus
  }
}];
